arguments.new_str:
namespace Warehouse;

public sealed class InventoryTracker
{
    private readonly Dictionary<string, int> _stock = new(StringComparer.OrdinalIgnoreCase);
    private readonly int _reorderThreshold;

    public InventoryTracker(int reorderThreshold = 10)
    {
        if (reorderThreshold < 0)
            throw new ArgumentOutOfRangeException(nameof(reorderThreshold));
        _reorderThreshold = reorderThreshold;
    }

    public int GetStockLevel(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        return _stock.TryGetValue(sku, out var level) ? level : 0;
    }

    public void AddStock(string sku, int quantity)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");

        _stock[sku] = GetStockLevel(sku) + quantity;
    }

    public void RemoveStock(string sku, int quantity)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");

        var current = GetStockLevel(sku);
        if (quantity > current)
            throw new InvalidOperationException($"Insufficient stock for '{sku}'. Available: {current}, Requested: {quantity}.");

        _stock[sku] = current - quantity;
    }

    public bool NeedsReorder(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        return GetStockLevel(sku) <= _reorderThreshold;
    }

    /// <summary>
    /// Transfers stock from this tracker (source warehouse) to a destination warehouse.
    /// </summary>
    public void TransferTo(InventoryTracker destination, string sku, int quantity)
    {
        ArgumentNullException.ThrowIfNull(destination);
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");

        RemoveStock(sku, quantity);
        destination.AddStock(sku, quantity);
    }
}

