using Warehouse;

namespace InventoryTracker.Tests;

[TestClass]
public class StockLevelTests
{
    private Warehouse.InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new Warehouse.InventoryTracker(reorderThreshold: 5);

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-999"));
    }

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("SKU-001", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_ExistingSku_AccumulatesQuantity()
    {
        _tracker.AddStock("SKU-001", 20);
        _tracker.AddStock("SKU-001", 30);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_IsCaseInsensitive()
    {
        _tracker.AddStock("sku-abc", 10);
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-ABC"));
    }

    [TestMethod]
    public void AddStock_ZeroQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.AddStock("SKU-001", 0));
    }

    [TestMethod]
    public void AddStock_NegativeQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.AddStock("SKU-001", -5));
    }

    [TestMethod]
    public void AddStock_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.AddStock(null!, 10));
    }

    [TestMethod]
    public void AddStock_WhitespaceSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.AddStock("   ", 10));
    }

    [TestMethod]
    public void GetStockLevel_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.GetStockLevel(null!));
    }

    [TestMethod]
    public void RemoveStock_ReducesLevel()
    {
        _tracker.AddStock("SKU-001", 40);
        _tracker.RemoveStock("SKU-001", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void RemoveStock_EntireQuantity_LeavesZero()
    {
        _tracker.AddStock("SKU-001", 10);
        _tracker.RemoveStock("SKU-001", 10);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void RemoveStock_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-001", 5);
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-001", 10));
    }

    [TestMethod]
    public void RemoveStock_ZeroQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.RemoveStock("SKU-001", 0));
    }

    [TestMethod]
    public void RemoveStock_NegativeQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.RemoveStock("SKU-001", -1));
    }
}

[TestClass]
public class ReorderAlertTests
{
    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        var tracker = new Warehouse.InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-001", 5);
        Assert.IsTrue(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsTrue()
    {
        var tracker = new Warehouse.InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-001", 10);
        Assert.IsTrue(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        var tracker = new Warehouse.InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-001", 11);
        Assert.IsFalse(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        var tracker = new Warehouse.InventoryTracker(reorderThreshold: 5);
        Assert.IsTrue(tracker.NeedsReorder("SKU-UNKNOWN"));
    }

    [TestMethod]
    public void NeedsReorder_AfterRemoval_TriggersAlert()
    {
        var tracker = new Warehouse.InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-001", 20);
        Assert.IsFalse(tracker.NeedsReorder("SKU-001"));

        tracker.RemoveStock("SKU-001", 15);
        Assert.IsTrue(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_NullSku_Throws()
    {
        var tracker = new Warehouse.InventoryTracker();
        Assert.ThrowsException<ArgumentException>(
            () => tracker.NeedsReorder(null!));
    }

    [TestMethod]
    public void Constructor_NegativeThreshold_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => new Warehouse.InventoryTracker(reorderThreshold: -1));
    }

    [TestMethod]
    public void Constructor_DefaultThreshold_IsReasonable()
    {
        var tracker = new Warehouse.InventoryTracker();
        tracker.AddStock("SKU-001", 10);
        // Default threshold is 10, so stock at 10 should need reorder
        Assert.IsTrue(tracker.NeedsReorder("SKU-001"));

        tracker.AddStock("SKU-001", 1);
        Assert.IsFalse(tracker.NeedsReorder("SKU-001"));
    }
}

[TestClass]
public class WarehouseTransferTests
{
    private Warehouse.InventoryTracker _source = null!;
    private Warehouse.InventoryTracker _destination = null!;

    [TestInitialize]
    public void Setup()
    {
        _source = new Warehouse.InventoryTracker(reorderThreshold: 5);
        _destination = new Warehouse.InventoryTracker(reorderThreshold: 5);
    }

    [TestMethod]
    public void TransferTo_MovesStockBetweenWarehouses()
    {
        _source.AddStock("SKU-001", 100);
        _source.TransferTo(_destination, "SKU-001", 40);

        Assert.AreEqual(60, _source.GetStockLevel("SKU-001"));
        Assert.AreEqual(40, _destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void TransferTo_EntireStock_EmptiesSource()
    {
        _source.AddStock("SKU-001", 25);
        _source.TransferTo(_destination, "SKU-001", 25);

        Assert.AreEqual(0, _source.GetStockLevel("SKU-001"));
        Assert.AreEqual(25, _destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void TransferTo_DestinationAlreadyHasStock_Accumulates()
    {
        _source.AddStock("SKU-001", 50);
        _destination.AddStock("SKU-001", 20);

        _source.TransferTo(_destination, "SKU-001", 30);

        Assert.AreEqual(20, _source.GetStockLevel("SKU-001"));
        Assert.AreEqual(50, _destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void TransferTo_InsufficientStock_Throws_AndNoSideEffects()
    {
        _source.AddStock("SKU-001", 10);
        _destination.AddStock("SKU-001", 5);

        Assert.ThrowsException<InvalidOperationException>(
            () => _source.TransferTo(_destination, "SKU-001", 20));

        // Verify no partial transfer occurred
        Assert.AreEqual(10, _source.GetStockLevel("SKU-001"));
        Assert.AreEqual(5, _destination.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void TransferTo_ZeroQuantity_Throws()
    {
        _source.AddStock("SKU-001", 10);
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _source.TransferTo(_destination, "SKU-001", 0));
    }

    [TestMethod]
    public void TransferTo_NullDestination_Throws()
    {
        _source.AddStock("SKU-001", 10);
        Assert.ThrowsException<ArgumentNullException>(
            () => _source.TransferTo(null!, "SKU-001", 5));
    }

    [TestMethod]
    public void TransferTo_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _source.TransferTo(_destination, null!, 5));
    }

    [TestMethod]
    public void TransferTo_TriggersReorderOnSource()
    {
        _source.AddStock("SKU-001", 8);
        Assert.IsFalse(_source.NeedsReorder("SKU-001"));

        _source.TransferTo(_destination, "SKU-001", 5);
        Assert.IsTrue(_source.NeedsReorder("SKU-001"));
    }
}

using Warehouse;

namespace InventoryTracker.Tests;

[TestClass]
public class StockLevelTests
{
